// 三载体一致:纯 JS,无 DOM/uplink/shadow 足迹
import skmeans from 'https://cdn.jsdelivr.net/npm/skmeans@0/+esm';         // default 导出函数
const res = skmeans(data.data, data.k, data.initial ?? null, data.iterations);
// res.idxs[i] = 第 i 点所属簇下标 · res.centroids[j] = 第 j 簇质心 · res.it = 迭代次数
const colored = data.data.map((p, i) => ({ point: p, cluster: res.idxs[i] }));  // 按簇染色画散点,叠加 res.centroids 作簇心
